custom_css:
#custom-logo-container {
  position: relative;
  display: inline-block;
  filter: drop-shadow(0 0 8px rgba(255, 255, 255, 0.8));
  animation: snow-glow 3s infinite alternate ease-in-out;
}

#custom-logo-container::before {
  content: '❄';
  position: absolute;
  top: -15px;
  left: 10%;
  font-size: 14px;
  color: white;
  animation: falling-snow 2s infinite linear;
}

#custom-logo-container::after {
  content: '🎅';
  position: absolute;
  top: -18px;
  right: -5px;
  font-size: 16px;
  transform: rotate(15deg);
}

#fallback-title {
  background: linear-gradient(to bottom, #ff0000 20%, #22c55e 50%, #eab308 90%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  font-weight: 900;
  position: relative;
}

@keyframes snow-glow {
  0% { filter: drop-shadow(0 0 5px #fff); }
  100% { filter: drop-shadow(0 0 15px #3b82f6); }
}

@keyframes falling-snow {
  0% { transform: translateY(0) translateX(0); opacity: 0; }
  50% { opacity: 1; }
  100% { transform: translateY(15px) translateX(5px); opacity: 0; }
}
